import React from 'react';
import JobCard from './JobCard';

const JobList = ({ jobs, variant, onSelectJob }) => {
    // Definisi gaya yang responsif
    const containerStyle = {
        display: 'grid',
        // Desktop: Berjajar (300px min), Mobile: 1 kolom penuh
        gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
        gap: 'clamp(15px, 3vw, 24px)', // Jarak antar kartu mengecil di HP
        width: '100%',
        padding: '0 10px'
    };

    return (
        <div style={containerStyle}>
            {jobs.map(job => (
                <div key={job.id} style={{ 
                    // Perbedaan UI: Tambahkan shadow/border lebih tipis di mobile
                    // agar tidak terlihat "penuh" di layar kecil
                    '@media (max-width: 600px)': {
                        padding: '16px'
                    }
                }}>
                    <JobCard 
                        job={job} 
                        isFull={variant === 'full'} 
                        onClick={() => onSelectJob && onSelectJob(job)}
                    />
                </div>
            ))}
        </div>
    );
};

export default JobList;
